import "fmt"

func main() {
	src := `package pkg

//go:embed a.txt b.txt
var a string

var (
	//go:embed c.txt
	c string
)
`
	fset := token.NewFileSet()
	f, err := parser.ParseFile(fset, "test.go", src, parser.ParseComments)
